import{_ as a,o as e,c as s,ae as l,j as t}from"./chunks/framework.CyZiF_rV.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"ru/limity/limity-api.md","filePath":"ru/limity/limity-api.md"}'),n={name:"ru/limity/limity-api.md"};function r(o,i,d,h,p,u){return e(),s("div",null,[...i[0]||(i[0]=[l(`<blockquote><p><strong>Translation.</strong> Original: <a href="https://github.com/CIRFMF/ksef-docs/blob/main/limity/limity-api.md" target="_blank" rel="noreferrer">limity/limity-api.md</a></p></blockquote><h2 id="лимиты-запросов-api" tabindex="-1">Лимиты запросов API <a class="header-anchor" href="#лимиты-запросов-api" aria-label="Permalink to &quot;Лимиты запросов API&quot;">​</a></h2><p>22.11.2025</p><p>В связи с масштабом работы KSeF и его публичным характером введены механизмы ограничения интенсивности запросов API. Их цель - защита стабильности системы, защита от киберугроз и обеспечение равных условий доступа для всех пользователей. Лимиты определяют максимальное количество запросов, которые можно выполнить за определенное время, и принуждают к такому способу интеграции, который соответствует принципам архитектуры системы.</p><h3 id="общие-принципы-лимитов" tabindex="-1">Общие принципы лимитов <a class="header-anchor" href="#общие-принципы-лимитов" aria-label="Permalink to &quot;Общие принципы лимитов&quot;">​</a></h3><h4 id="_1-способ-начисления-лимитов" tabindex="-1">1. Способ начисления лимитов <a class="header-anchor" href="#_1-способ-начисления-лимитов" aria-label="Permalink to &quot;1. Способ начисления лимитов&quot;">​</a></h4><p>Все запросы к API KSeF подлежат лимитам. Эти ограничения охватывают каждый вызов защищенной конечной точки. Для целей учета трафика запросы группируются по паре: контекст и IP-адрес.</p><ul><li><strong>контекст</strong> - определяемый <code>ContextIdentifier</code> (<code>Nip</code>, <code>InternalId</code> или <code>NipVatUe</code>), переданным при аутентификации.</li><li><strong>IP-адрес</strong> - IP-адрес, с которого устанавливается сетевое соединение.</li></ul><p>Лимиты запросов начисляются независимо для каждой пары: контекст и IP-адрес. Это означает, что трафик в том же контексте, но с разных IP-адресов, учитывается отдельно.</p><p>Пример<br> Бухгалтерская фирма A скачивает счета от имени компании B, используя контекст компании B (NIP) и подключаясь к KSeF с адреса IP1. Одновременно компания B скачивает счета самостоятельно, в том же контексте (своем NIP), но с другого IP-адреса - IP2. Несмотря на общий контекст, разные IP-адреса приводят к тому, что лимиты начисляются независимо. В такой ситуации система рассматривает каждое соединение как отдельную пару (контекст + IP-адрес) и начисляет лимиты независимо: отдельно для бухгалтерской фирмы A и отдельно для компании B.</p><p><strong>Единицы лимитов</strong><br> В таблицах лимитов используются следующие обозначения:</p><ul><li>req/s - количество запросов в секунду,</li><li>req/min - количество запросов в минуту,</li><li>req/h - количество запросов в час.</li></ul><p><strong>Модель начисления лимитов (скользящее временное окно - sliding/rolling window)</strong><br> Лимиты применяются в модели скользящего временного окна. В каждый момент подсчитываются запросы, выполненные в период:</p><ul><li>для порога req/h - за последние 60 минут,</li><li>для порога req/min - за последние 60 секунд,</li><li>для порога req/s - за последнюю секунду.</li></ul><p>Окна не выравниваются по полным часам или минутам (не &quot;сбрасываются&quot; в :00). Все пороги (req/s, req/min, req/h) действуют параллельно - блокировка срабатывает при первом превышении любого из них.</p><h4 id="_2-при-превышении-лимита-система-блокирует-доступ-к-api" tabindex="-1">2. При превышении лимита система блокирует доступ к API <a class="header-anchor" href="#_2-при-превышении-лимита-система-блокирует-доступ-к-api" aria-label="Permalink to &quot;2. При превышении лимита система блокирует доступ к API&quot;">​</a></h4><p>В случае превышения лимитов запросов API возвращается код HTTP <strong>429 Too Many Requests</strong>, а последующие запросы временно блокируются.<br> Период блокировки <strong>динамический</strong> и зависит от частоты и масштаба превышений. Точное время блокировки возвращается в заголовке ответа <code>Retry-After</code> (в секундах). Многократные превышения могут привести к значительному продлению блокировки.</p><p>Пример ответа 429:</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">HTTP/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1.1</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 429</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Too Many Requests</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Content-Type: application/json</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Retry-After: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">30</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;status&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;code&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">429</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;description&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Too Many Requests&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;details&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Превышен лимит 20 запросов в минуту. Попробуйте снова через 30 секунд.&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h4 id="_3-регистрация-превышении" tabindex="-1">3. Регистрация превышений <a class="header-anchor" href="#_3-регистрация-превышении" aria-label="Permalink to &quot;3. Регистрация превышений&quot;">​</a></h4><p>Все случаи превышения лимитов запросов регистрируются и анализируются механизмами безопасности. Эти данные служат для мониторинга стабильности API и обнаружения потенциальных злоупотреблений. Система обращает особое внимание на паттерны, указывающие на попытки обхода лимитов, например, через параллельное и системное использование множества IP-адресов в рамках одного контекста. Такие действия могут быть признаны угрозой безопасности.</p><p>В случае повторяющихся нарушений или экстремальной нагрузки система может автоматически применить защитные действия, такие как:</p><ul><li>блокировка доступа к API KSeF для данного субъекта или диапазона IP-адресов,</li><li>ограничение доступности для наиболее нагружающих контекстов.</li></ul><h4 id="_4-более-высокие-лимиты-в-ночные-часы" tabindex="-1">4. Более высокие лимиты в ночные часы <a class="header-anchor" href="#_4-более-высокие-лимиты-в-ночные-часы" aria-label="Permalink to &quot;4. Более высокие лимиты в ночные часы&quot;">​</a></h4><p>В часы с 20:00 до 06:00 действуют более высокие лимиты скачивания, чем в течение дня. Подробные значения будут определены в начальный период работы KSeF 2.0, после настройки параметров к реальным нагрузкам.</p><h4 id="_5-предварительные-предположения-лимитов" tabindex="-1">5. Предварительные предположения лимитов <a class="header-anchor" href="#_5-предварительные-предположения-лимитов" aria-label="Permalink to &quot;5. Предварительные предположения лимитов&quot;">​</a></h4><p>Лимиты запросов API были определены на основе предполагаемых сценариев использования системы и моделей нагрузок.</p><p>Фактический характер трафика будет зависеть от способа реализации интеграции во внешних системах и от создаваемых ими паттернов нагрузки. Это означает, что лимиты, установленные на этапе проектирования, могут отличаться от значений, поддерживаемых в производственной среде.</p><p>По этой причине лимиты носят динамический характер и могут корректироваться в зависимости от эксплуатационных условий и поведения интеграторов. В частности, допускается их временное снижение в случае интенсивного или неэффективного использования API.</p><h3 id="лимиты-в-средах" tabindex="-1">Лимиты в средах <a class="header-anchor" href="#лимиты-в-средах" aria-label="Permalink to &quot;Лимиты в средах&quot;">​</a></h3><p><strong>Среда TE (тестовая)</strong> В среде TE лимиты настроены так, чтобы обеспечить свободную работу интеграторов и тестирование интеграции без риска блокировок. Стандартные значения лимитов <strong>в десять раз выше</strong>, чем в продакшене, что позволяет проводить интенсивные тесты. Дополнительно, благодаря предоставленным конечным точкам можно моделировать различные сценарии:</p><ul><li><a href="https://api-test.ksef.mf.gov.pl/docs/v2/index.html#tag/Limity-i-ograniczenia/paths/~1testdata~1rate-limits~1production/post" target="_blank" rel="noreferrer">POST /testdata/rate-limits/production</a> - активирует лимиты как в продакшене (PRD),</li><li><a href="https://api-test.ksef.mf.gov.pl/docs/v2/index.html#tag/Limity-i-ograniczenia/paths/~1testdata~1rate-limits/post" target="_blank" rel="noreferrer">POST /testdata/rate-limits</a> - позволяет установить собственные значения,</li><li><a href="https://api-test.ksef.mf.gov.pl/docs/v2/index.html#tag/Limity-i-ograniczenia/paths/~1testdata~1rate-limits/delete" target="_blank" rel="noreferrer">DELETE /testdata/rate-limits</a> - восстанавливает стандартные лимиты среды TE.</li></ul><p><strong>Среда DEMO (предпродакшн)</strong> В среде DEMO действуют <strong>те же лимиты, что и в продакшене</strong> для данного контекста. Эти значения <strong>реплицируются с PRD</strong> и служат для финальной валидации производительности и стабильности интеграции перед производственным внедрением.</p><p><strong>Среда PRD (продакшн)</strong> В среде PRD применяются <strong>стандартные лимиты</strong>, определенные в данной документации. В обоснованных случаях - например, при большом масштабе обработки счетов - предусмотрена возможность <strong>подачи заявки на повышение лимитов</strong> через специальную форму (в подготовке).</p><h2 id="скачивание-счетов-лимиты" tabindex="-1">Скачивание счетов - лимиты <a class="header-anchor" href="#скачивание-счетов-лимиты" aria-label="Permalink to &quot;Скачивание счетов - лимиты&quot;">​</a></h2><h3 id="архитектурные-принципы" tabindex="-1">Архитектурные принципы <a class="header-anchor" href="#архитектурные-принципы" aria-label="Permalink to &quot;Архитектурные принципы&quot;">​</a></h3><p>API KSeF в области скачивания счетов было разработано как механизм <strong>синхронизации документов</strong> между центральным репозиторием и локальной базой данных внешних систем. Ключевым принципом является выполнение бизнес-операций, таких как поиск, фильтрация или отчетность, на данных, хранящихся локально, которые были предварительно синхронизированы с KSeF. Такой подход повышает стабильность работы, минимизирует риск перегрузки системы и позволяет более гибко использовать данные клиентскими приложениями.</p><p>API KSeF в области скачивания счетов не предназначено для обслуживания прямых операций конечных пользователей в реальном времени. Это означает, что оно не должно использоваться для:</p><ul><li>скачивания отдельных счетов по запросу пользователя, например, просмотр счета,</li><li>скачивания списка метаданных счетов или инициации экспорта пакетов в реакции на текущие действия в приложении, за исключением ситуаций, когда пользователь сознательно запускает синхронизацию данных.</li></ul><h3 id="рекомендуемыи-способ-интеграции-в-области-скачивания" tabindex="-1">Рекомендуемый способ интеграции в области скачивания <a class="header-anchor" href="#рекомендуемыи-способ-интеграции-в-области-скачивания" aria-label="Permalink to &quot;Рекомендуемый способ интеграции в области скачивания&quot;">​</a></h3><p>Для инкрементальной синхронизации используется конечная точка <code>/invoices/query/metadata</code>. Подробные принципы инкрементальной синхронизации описаны в отдельном документе.</p><p>В зависимости от объема счетов можно применять различные подходы к их скачиванию:</p><ol><li><strong>Сценарии низкого объема</strong> - если количество счетов ограничено и может быть обработано в рамках доступных лимитов за ожидаемое время, можно скачивать их синхронно, вызывая <code>/invoices/ksef/{ksefNumber}</code> для выбранных документов.</li><li><strong>Сценарии высокого объема</strong> - если количество документов значительно и обработка в синхронном режиме становится непрактичной, рекомендуется использовать механизм экспорта (<code>/invoices/exports</code>). Экспорт работает асинхронно, ставится в очередь и благодаря этому не влияет негативно на производительность системы.</li><li><strong>Бизнес-операции</strong> - независимо от выбранной стратегии, все действия пользователей (поиск, фильтрация, отчетность) должны выполняться на <strong>локальной базе данных</strong>, синхронизированной ранее с KSeF.</li></ol><h3 id="режимы-синхронизации-и-скачивания-счетов" tabindex="-1">Режимы синхронизации и скачивания счетов <a class="header-anchor" href="#режимы-синхронизации-и-скачивания-счетов" aria-label="Permalink to &quot;Режимы синхронизации и скачивания счетов&quot;">​</a></h3><p>Скачивание счета в бухгалтерскую систему может осуществляться в трех режимах:</p><ol><li><strong>По запросу пользователя</strong> - инкрементальная синхронизация запускается <strong>вручную</strong> пользователем от последней подтвержденной контрольной точки.</li><li><strong>Циклически</strong> - инкрементальная синхронизация выполняется автоматически согласно расписанию системы.</li><li><strong>Смешанный режим</strong> - инкрементальная синхронизация работает циклически, а дополнительно пользователь может запустить ее вручную по требованию.</li></ol><h3 id="частота-опроса" tabindex="-1">Частота опроса <a class="header-anchor" href="#частота-опроса" aria-label="Permalink to &quot;Частота опроса&quot;">​</a></h3><ul><li><strong>Не рекомендуются расписания с высокой частотой</strong>. В продакшн-среде циклический интервал не должен быть короче 15 минут для каждого субъекта, присутствующего на счете (Субъект 1, Субъект 2, Субъект 3, Уполномоченный субъект).</li><li><strong>Профили низкого объема.</strong> Рекомендуется скачивание по требованию, дополненное циклом например раз в сутки в ночном окне.</li><li><strong>Дата получения счета.</strong> Датой получения счета является дата присвоения номера KSeF. Этот номер присваивается автоматически системой в момент обработки счета и не зависит от момента его скачивания в бухгалтерскую систему.</li></ul><h3 id="примеры-нерекомендуемои-реализации" tabindex="-1">Примеры нерекомендуемой реализации <a class="header-anchor" href="#примеры-нерекомендуемои-реализации" aria-label="Permalink to &quot;Примеры нерекомендуемой реализации&quot;">​</a></h3><p>Неправильная интеграция может привести к блокировке в API. К наиболее частым ошибкам относятся:</p><ol><li>Синхронизация исключительно через скачивание отдельных счетов (синхронный путь), без использования экспорта пакетов счетов. Такой подход допустим только в профилях с низким объемом; при большем количестве документов следует использовать механизм <code>/invoices/exports</code>.</li><li>Обслуживание запросов конечных пользователей (например, отображение полного содержания счета в приложении, скачивание XML-файла) через прямые вызовы API KSeF вместо использования локальной базы.</li></ol><h3 id="подробные-лимиты" tabindex="-1">Подробные лимиты <a class="header-anchor" href="#подробные-лимиты" aria-label="Permalink to &quot;Подробные лимиты&quot;">​</a></h3>`,52),t("table",{tabindex:"0"},[t("thead",null,[t("tr",null,[t("th",null,"Конечная точка"),t("th"),t("th",null,"req/s"),t("th",null,"req/min"),t("th",null,"req/h")])]),t("tbody",null,[t("tr",null,[t("td",null,"Получение списка метаданных счетов"),t("td",null,"POST /invoices/query/metadata"),t("td",null,"8"),t("td",null,"16"),t("td",null,"20")]),t("tr",null,[t("td",null,"Экспорт пакета счетов"),t("td",null,"POST /invoices/exports"),t("td",null,"4"),t("td",null,"8"),t("td",null,"20")]),t("tr",null,[t("td",null,"Получение статуса экспорта пакета счетов"),t("td",{referenceNumber:""},"/invoices/exports/"),t("td",null,"10"),t("td",null,"60"),t("td",null,"600")]),t("tr",null,[t("td",null,"Получение счета по номеру KSeF"),t("td",{ksefNumber:""},"GET /invoices/ksef/"),t("td",null,"8"),t("td",null,"16"),t("td",null,"64")])])],-1),l('<p><strong>Примечание:</strong> Если в бизнес-сценариях организации доступных лимитов скачивания счетов недостаточно, просим обратиться в службу поддержки KSeF для индивидуального анализа и подбора соответствующего решения.</p><h2 id="отправка-счетов-лимиты" tabindex="-1">Отправка счетов - лимиты <a class="header-anchor" href="#отправка-счетов-лимиты" aria-label="Permalink to &quot;Отправка счетов - лимиты&quot;">​</a></h2><h3 id="архитектурные-принципы-1" tabindex="-1">Архитектурные принципы <a class="header-anchor" href="#архитектурные-принципы-1" aria-label="Permalink to &quot;Архитектурные принципы&quot;">​</a></h3><ul><li>Отправка счетов независимо от типа отправки ставится в очередь.</li><li>Обработка оптимизирована для максимально быстрого подтверждения правильности счета и возврата номера KSeF.</li></ul><h4 id="пакетная-отправка-пакеты-счетов" tabindex="-1">Пакетная отправка (пакеты счетов): <a class="header-anchor" href="#пакетная-отправка-пакеты-счетов" aria-label="Permalink to &quot;Пакетная отправка (пакеты счетов):&quot;">​</a></h4><ul><li>Пакет счетов рассматривается как одно сообщение в очереди (ссылка на пакет вместо отдельных записей для каждого счета) и обрабатывается с тем же приоритетом, что и отдельный документ.</li><li>Отправка в пакете ограничивает сетевые и операционные издержки, поскольку: <ul><li>выполняется меньшее количество HTTP-запросов,</li><li>операции с содержимым (расшифровка, валидация, запись) выполняются в пакетном режиме, что представляет наиболее эффективный способ обработки множества документов одновременно.</li></ul></li><li>Сжатие пакета. Благодаря XML-формату и высокой повторяемости элементов между счетами (постоянная структура, похожие названия полей, повторяющиеся блоки) достигается обычно очень благоприятный коэффициент сжатия, что значительно уменьшает объем данных и сокращает время передачи. На практике быстрее отправить один пакет, содержащий например 100 счетов, чем 100 отдельных счетов в интерактивной сессии.</li><li>Лимиты. Механизм лимитов работает независимо от режима отправки. Пакетная отправка по своей природе уменьшает количество запросов и облегчает эффективное использование доступных лимитов.</li><li>Применение. Пакетный режим рекомендуется везде, где в одном операционном окне передается более одного документа. В частности, хорошо подходит при циклических расчетах клиентов, в электронной коммерции и в автоматизированных процессах выставления счетов.</li></ul><p>Примерные сценарии применения пакетного режима:</p><ul><li><strong>Интернет-магазин (e-commerce).</strong> Заказы и платежи обрабатываются асинхронно, а счета выставляются автоматически системой ERP или модулем выставления счетов. Отдельный счет не должен отправляться в KSeF сразу после выставления. Выделенный процесс может агрегировать выставленные счета и циклически - например, каждые 5 минут - отправлять их в пакетах в KSeF, что значительно ограничивает количество HTTP-запросов и оптимизирует использование лимитов.</li><li><strong>Подписные услуги / циклические расчеты.</strong> Счета генерируются сводно раз в день или раз в месяц (например, в телекоммуникациях или медиа) и отправляются в одном пакете в рамках запланированной пакетной сессии.</li><li><strong>Автоматизированные процессы выставления счетов на предприятиях.</strong> Встречаются например в секторе дистрибуции, логистики, производства или услуг, заказываемых в модели B2B. Счета генерируются автоматически на основе системных событий (поставки, выполнение заказов) и отправляются сводно, например, после завершения операций.</li></ul><p><strong>Рекомендация:</strong> для обеспечения максимальной эффективности интеграции рекомендуется агрегировать документы в одной пакетной сессии везде, где это возможно с точки зрения бизнес-процессов. Это позволяет ограничить количество запросов API и оптимизирует использование доступных лимитов.</p><p><strong>Подробные лимиты</strong></p><table tabindex="0"><thead><tr><th>Конечная точка</th><th></th><th>req/s</th><th>req/min</th><th>req/h</th></tr></thead><tbody><tr><td>Открытие пакетной сессии *</td><td>POST /sessions/batch</td><td>10</td><td>20</td><td>60</td></tr><tr><td>Закрытие пакетной сессии</td><td>POST /sessions/batch/{referenceNumber}/close</td><td>10</td><td>20</td><td>60</td></tr></tbody></table><p><strong>Отправка частей пакета</strong> - запросы, отправляющие части пакета в рамках одной пакетной сессии, не подлежат лимитам API. В случае пакетов, разделенных на множество частей, рекомендуется их параллельная (многопоточная) отправка, что значительно сокращает время отправки.</p><h4 id="интерактивная-отправка-по-одному" tabindex="-1">Интерактивная отправка (по одному) <a class="header-anchor" href="#интерактивная-отправка-по-одному" aria-label="Permalink to &quot;Интерактивная отправка (по одному)&quot;">​</a></h4><p>Интерактивный режим разработан для сценариев, требующих быстрой регистрации отдельных счетов и немедленного получения номера KSeF. В отличие от пакетной сессии, каждый счет отправляется независимо в рамках активной интерактивной сессии. Его цель - максимальное сокращение времени, необходимого для получения номера KSeF для отдельного документа. Применение включает сценарии с низким объемом, в которых отправляются отдельные счета.</p><p>Примерные сценарии применения интерактивного режима:</p><ul><li><strong>Точка розничных продаж (POS)</strong>. После завершения транзакции выставляется счет, а система регистрирует его немедленно в KSeF и возвращает номер KSeF для печати или представления клиенту.</li><li><strong>Мобильные приложения и легкие торговые системы</strong>, не имеющие механизма очередей или буферизации, отправляющие счета сразу после их выставления.</li><li><strong>Единичные или нерегулярные события</strong> например отдельный корректировочный счет.</li></ul><p>Интерактивный режим, несмотря на больший сетевой издержки в случае больших объемов, является необходимым дополнением пакетного режима в сценариях, требующих текущей реакции или немедленной регистрации документа в KSeF. Его следует применять исключительно там, где немедленная обработка счета критична для бизнес-процесса или когда масштаб операций не оправдывает использование пакетной сессии.</p><p><strong>Подробные лимиты</strong></p><table tabindex="0"><thead><tr><th>Конечная точка</th><th></th><th>req/s</th><th>req/min</th><th>req/h</th></tr></thead><tbody><tr><td>Открытие интерактивной сессии</td><td>POST /sessions/online</td><td>10</td><td>30</td><td>120</td></tr><tr><td>Отправка счета *</td><td>POST /sessions/online/{referenceNumber}/invoices</td><td>10</td><td>30</td><td>180</td></tr><tr><td>Закрытие интерактивной сессии</td><td>POST /sessions/online/{referenceNumber}/close</td><td>10</td><td>30</td><td>120</td></tr></tbody></table><p>* <strong>Примечание:</strong> Если в бизнес-сценариях организации регулярно достигаются лимиты отправки в интерактивной сессии, в первую очередь следует рассмотреть применение пакетного режима, который позволяет более эффективно использовать доступные ресурсы и лимиты. В ситуациях, когда использование интерактивной сессии необходимо, а достигаемые лимиты остаются недостаточными, просим обратиться в службу поддержки KSeF для индивидуального анализа и помощи в подборе решения.</p><h3 id="статус-сессии-и-счетов" tabindex="-1">Статус сессий и счетов <a class="header-anchor" href="#статус-сессии-и-счетов" aria-label="Permalink to &quot;Статус сессий и счетов&quot;">​</a></h3><p><strong>Подробные лимиты</strong></p>',22),t("table",{tabindex:"0"},[t("thead",null,[t("tr",null,[t("th",null,"Конечная точка"),t("th"),t("th",null,"req/s"),t("th",null,"req/min"),t("th",null,"req/h")])]),t("tbody",null,[t("tr",null,[t("td",null,"Получение статуса счета из сессии"),t("td",{invoiceReferenceNumber:""},"GET /sessions/{referenceNumber}/invoices/"),t("td",null,"30"),t("td",null,"120"),t("td",null,"1200")]),t("tr",null,[t("td",null,"Получение списка сессий"),t("td",null,"GET /sessions"),t("td",null,"5"),t("td",null,"10"),t("td",null,"60")]),t("tr",null,[t("td",null,"Получение счетов сессии"),t("td",null,"GET /sessions/{referenceNumber}/invoices"),t("td",null,"10"),t("td",null,"20"),t("td",null,"200")]),t("tr",null,[t("td",null,"Получение неправильно обработанных счетов сессии"),t("td",null,"GET /sessions/{referenceNumber}/invoices/failed"),t("td",null,"10"),t("td",null,"20"),t("td",null,"200")]),t("tr",null,[t("td",null,"Остальные"),t("td",null,"GET /sessions/*"),t("td",null,"10"),t("td",null,"120"),t("td",null,"1200")])])],-1),l('<h2 id="остальные" tabindex="-1">Остальные <a class="header-anchor" href="#остальные" aria-label="Permalink to &quot;Остальные&quot;">​</a></h2><p>Стандартные лимиты действуют для всех ресурсов API, которые не имеют определенных подробных значений в данной документации. Каждая такая конечная точка имеет собственный счетчик лимитов, а ее запросы не влияют на другие ресурсы.</p><p>Эти лимиты касаются исключительно защищенных ресурсов. Они не охватывают публичные ресурсы API, такие как <code>/auth/challenge</code>, которые не требуют аутентификации и имеют собственные механизмы защиты - лимит составляет 60 запросов в секунду для одного IP-адреса.</p><table tabindex="0"><thead><tr><th>Конечная точка</th><th></th><th>req/s</th><th>req/min</th><th>req/h</th></tr></thead><tbody><tr><td>Остальные</td><td>POST/GET /*</td><td>10</td><td>30</td><td>120</td></tr></tbody></table><p>Связанные документы:</p><ul><li><a href="./limity.html">Лимиты</a></li></ul>',6)])])}const k=a(n,[["render",r]]);export{g as __pageData,k as default};
